@rendermode InteractiveServer
@using sv_f10127acd42143d7bdb9f6f849946419.Models
@using sv_f10127acd42143d7bdb9f6f849946419.Services
@inject WizardStateStore Store
@inject IHttpContextAccessor HttpContextAccessor
@inject NavigationManager Nav

<PageTitle>Apply – Review</PageTitle>

<h1>Step 4: Review Your Application</h1>

@if (state is not null)
{
    <h4>Personal Information</h4>
    <dl class="row">
        <dt class="col-sm-3">Name</dt>
        <dd class="col-sm-9">@state.Name</dd>
        <dt class="col-sm-3">Email</dt>
        <dd class="col-sm-9">@state.Email</dd>
    </dl>

    <h4>Experience</h4>
    @if (state.Jobs.Count == 0)
    {
        <p class="text-muted">No jobs entered.</p>
    }
    else
    {
        <table class="table">
            <thead>
                <tr><th>Company</th><th>Title</th><th>Years</th></tr>
            </thead>
            <tbody>
                @foreach (var job in state.Jobs)
                {
                    <tr><td>@job.Company</td><td>@job.Title</td><td>@job.Years</td></tr>
                }
            </tbody>
        </table>
    }

    <h4>References</h4>
    @if (state.References.Count == 0)
    {
        <p class="text-muted">No references entered.</p>
    }
    else
    {
        <table class="table">
            <thead>
                <tr><th>Name</th><th>Email</th><th>Relationship</th></tr>
            </thead>
            <tbody>
                @foreach (var r in state.References)
                {
                    <tr><td>@r.Name</td><td>@r.Email</td><td>@r.Relationship</td></tr>
                }
            </tbody>
        </table>
    }

    <div>
        <button class="btn btn-secondary me-2" @onclick="Back">← Back</button>
        <button class="btn btn-success" @onclick="Submit">Submit Application</button>
    </div>

    @if (submitted)
    {
        <div class="alert alert-success mt-3">Application submitted!</div>
    }
}

@code {
    private string? sessionId;
    private WizardState? state;
    private bool submitted;

    protected override void OnInitialized()
    {
        sessionId = HttpContextAccessor.HttpContext?.Session.Id;
        if (sessionId is not null)
        {
            state = Store.GetOrCreate(sessionId);
        }
    }

    private void Back() => Nav.NavigateTo("/apply/references");

    private void Submit()
    {
        submitted = true;
        // In a real app you'd persist and then clear:
        // if (sessionId is not null) Store.Remove(sessionId);
    }
}

