<PageTitle>Apply – Experience</PageTitle>

<h1>Step 2: Experience</h1>

@for (var i = 0; i < jobs.Count; i++)
{
    var index = i;
    <div class="card mb-3 p-3">
        <div class="mb-2">
            <label class="form-label">Company</label>
            <input class="form-control" @bind="jobs[index].Company" />
        </div>
        <div class="mb-2">
            <label class="form-label">Title</label>
            <input class="form-control" @bind="jobs[index].Title" />
        </div>
        <div class="mb-2">
            <label class="form-label">Years</label>
            <input class="form-control" @bind="jobs[index].Years" />
        </div>
        <button class="btn btn-outline-danger btn-sm" @onclick="() => jobs.RemoveAt(index)">Remove</button>
    </div>
}

<button class="btn btn-outline-secondary mb-3" @onclick="() => jobs.Add(new())">+ Add Job</button>

<div>
    <button class="btn btn-secondary me-2" @onclick="Back">← Back</button>
    <button class="btn btn-primary" @onclick="Next">Next →</button>
</div>

@code {
    private string? sessionId;
    private List<JobEntry> jobs = [];

    protected override void OnInitialized()
    {
        sessionId = HttpContextAccessor.HttpContext?.Session.Id;
        if (sessionId is null) return;

        var state = Store.GetOrCreate(sessionId);
        // Deep-copy so edits don't mutate the store until the user clicks Next.
        jobs = state.Jobs.Select(j => new JobEntry
        {
            Company = j.Company,
            Title = j.Title,
            Years = j.Years
        }).ToList();
    }

    private void Back()
    {
        Save();
        Nav.NavigateTo("/apply/personal-info");
    }

    private void Next()
    {
        Save();
        Nav.NavigateTo("/apply/references");
    }

    private void Save()
    {
        if (sessionId is null) return;
        var state = Store.GetOrCreate(sessionId);
        state.Jobs = jobs;
        if (state.CompletedStep < 2) state.CompletedStep = 2;
    }
}

