    @if (state.Jobs.Count == 0)
    {
        <p class="text-muted">No jobs entered.</p>
    }
    else
    {
        <table class="table">
            <thead>
                <tr><th>Company</th><th>Title</th><th>Years</th></tr>
            </thead>
            <tbody>
                @foreach (var job in state.Jobs)
                {
                    <tr><td>@job.Company</td><td>@job.Title</td><td>@job.Years</td></tr>
                }
            </tbody>
        </table>
    }

    <h4>References</h4>
    @if (state.References.Count == 0)
    {
        <p class="text-muted">No references entered.</p>
    }
    else
    {
        <table class="table">
            <thead>
                <tr><th>Name</th><th>Email</th><th>Relationship</th></tr>
            </thead>
            <tbody>
                @foreach (var r in state.References)
                {
                    <tr><td>@r.Name</td><td>@r.Email</td><td>@r.Relationship</td></tr>
                }
            </tbody>
        </table>
    }

    <div>
        <button class="btn btn-secondary me-2" @onclick="Back">← Back</button>
        <button class="btn btn-success" @onclick="Submit">Submit Application</button>
    </div>

    @if (submitted)
    {
        <div class="alert alert-success mt-3">Application submitted!</div>
    }
}

@code {
