arguments.new_str:
@inherits LayoutComponentBase
@inject NavigationManager Nav

@{
    var steps = new (string Href, string Label)[]
    {
        ("/apply/personal-info", "Personal Info"),
        ("/apply/experience",    "Experience"),
        ("/apply/references",    "References"),
        ("/apply/review",        "Review"),
    };

    var uri = Nav.ToBaseRelativePath(Nav.Uri).TrimEnd('/');
    var currentStep = Array.FindIndex(steps, s => uri.Equals(s.Href.TrimStart('/'), StringComparison.OrdinalIgnoreCase));
    var isWizard = currentStep >= 0;
}

<div class="page">
    <div class="sidebar">
        <NavMenu />
    </div>

    <main>
        <div class="top-row px-4">
            @if (isWizard)
            {
                <nav aria-label="Application progress" class="d-flex align-items-center gap-3 w-100">
                    <span class="fw-bold">Step @(currentStep + 1) of @steps.Length</span>
                    <div class="progress flex-grow-1" style="height: 8px;">
                        <div class="progress-bar" role="progressbar"
                             style="width: @((currentStep + 1) * 100 / steps.Length)%"
                             aria-valuenow="@(currentStep + 1)" aria-valuemin="1" aria-valuemax="@steps.Length">
                        </div>
                    </div>
                    @foreach (var (href, label) in steps)
                    {
                        var active = uri.Equals(href.TrimStart('/'), StringComparison.OrdinalIgnoreCase);
                        <a href="@href" class="text-decoration-none @(active ? "fw-bold" : "text-muted")">@label</a>
                    }
                </nav>
            }
            else
            {
                <a href="https://learn.microsoft.com/aspnet/core/" target="_blank">About</a>
            }
        </div>

        <article class="content px-4">
            @Body
        </article>
    </main>
</div>

